require_once __DIR__.'/../lib/admin_auth.php'; require_once __DIR__.'/../lib/location_hours.php'; require_once __DIR__.'/../lib/admin_review.php'; craftcrawl_require_admin(); include '../db.php';
$id=filter_var($_GET['id']??null,FILTER_VALIDATE_INT); if(!$id) craftcrawl_redirect('admin/dashboard.php');
$stmt=$conn->prepare("SELECT id,name FROM locations WHERE id=?");$stmt->bind_param('i',$id);$stmt->execute();$location=$stmt->get_result()->fetch_assoc(); if(!$location)craftcrawl_redirect('admin/dashboard.php');
$hours=craftcrawl_location_hours_for_form($conn,$id); $message=null;
$return_to = trim($_GET['return_to'] ?? $_POST['return_to'] ?? '');
$allowed_returns = ['readiness' => 'readiness.php', 'reports' => 'reports.php', 'location_detail' => 'location_detail.php?id=' . $id, 'recovery' => 'recovery.php'];
$redirect_target = isset($allowed_returns[$return_to]) ? 'admin/' . $allowed_returns[$return_to] : 'admin/location_detail.php?id=' . $id;
if($_SERVER['REQUEST_METHOD']==='POST'){craftcrawl_verify_csrf();$hours=craftcrawl_business_hours_from_post($_POST);$err=craftcrawl_validate_business_hours($hours);if($err){$message=$err;}else{$conn->begin_transaction();craftcrawl_save_location_hours($conn,$id,$hours,'admin_manual');$u=$conn->prepare("UPDATE location_hours SET verifiedAt=NOW(),verifiedByAdminId=? WHERE location_id=?");$u->bind_param('ii',$_SESSION['admin_id'],$id);$u->execute();craftcrawl_log_admin_review_action($conn,(int)$_SESSION['admin_id'],'location',$id,'approved','Hours verified');$conn->commit();craftcrawl_redirect($redirect_target . (strpos($redirect_target, '?') !== false ? '&' : '?') . 'message=hours_saved');}}
$admin_page_title = craftcrawl_admin_escape($location['name']) . ' Hours';
$admin_page_subtitle = 'Edit and verify business hours.';
