        <a href="<?php echo craftcrawl_admin_escape(isset($allowed_returns[$return_to]) ? $allowed_returns[$return_to] : 'location_detail.php?id=' . $id); ?>">Back</a><?php if($message):?><p class="form-message form-message-error"><?php echo craftcrawl_admin_escape($message);?></p><?php endif;?><form method="POST"><?php echo craftcrawl_csrf_input();?><fieldset class="business-hours-editor"><legend>Location Hours</legend><p class="form-help">For late-night hours, choose the opening day and set the close time after midnight. Example: Friday 4:00 PM to 2:00 AM means check-ins stay available until Saturday 2:00 AM.</p><div class="business-hours-bulk" data-business-hours-bulk><div class="business-hours-bulk-times"><label>Opens<input type="time" data-hours-template-open></label><label>Closes<input type="time" data-hours-template-close></label><label class="business-hours-bulk-closed"><input type="checkbox" data-hours-template-closed>Closed</label></div><div class="business-hours-bulk-days" aria-label="Days to update"><?php foreach($hours as $day=>$h):?><label><input type="checkbox" value="<?php echo craftcrawl_admin_escape($day);?>" data-hours-target-day><?php echo craftcrawl_admin_escape(substr($h['day_label'],0,3));?></label><?php endforeach;?></div><div class="business-hours-bulk-actions"><button type="button" data-hours-select="weekdays">Weekdays</button><button type="button" data-hours-select="weekend">Weekend</button><button type="button" data-hours-select="all">All Days</button><button type="button" data-hours-select="clear">Clear</button><button type="button" data-hours-apply>Apply to Selected</button></div></div><?php foreach($hours as $day=>$h):?><div class="business-hours-row" data-hours-row="<?php echo craftcrawl_admin_escape($day);?>"><span><?php echo craftcrawl_admin_escape($h['day_label']);?></span><label><input type="checkbox" name="hours_closed[<?php echo craftcrawl_admin_escape($day);?>]" value="1" data-hours-closed <?php echo $h['is_closed']?'checked':'';?>>Closed</label><label>Opens<input type="time" name="hours_open[<?php echo craftcrawl_admin_escape($day);?>]" value="<?php echo craftcrawl_admin_escape($h['opens_at']);?>" data-hours-open></label><label>Closes<input type="time" name="hours_close[<?php echo craftcrawl_admin_escape($day);?>]" value="<?php echo craftcrawl_admin_escape($h['closes_at']);?>" data-hours-close></label></div><?php endforeach;?></fieldset><button>Save verified hours</button></form>
